const getTier   = m => TIERS.find(t=>m>=t.min12m&&m<=t.max12m)||TIERS[0]
const getNext   = m => { const t=getTier(m); return t.id<4?TIERS[t.id]:null }
const getProg   = m => { const t=getTier(m); if(t.id===4)return 100; return Math.min(100,Math.round(((m-t.min12m)/(t.max12m-t.min12m+1))*100)) }

// ─── HELPERS ─────────────────────────────────────────────────────────────────
const shuffle = a => { const b=[...a]; for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]]}; return b }

