// ─── QUIZ ENGINE ──────────────────────────────────────────────────────────────
function QuizEngine({questions,title,onDone,onAddCorks}) {
  const qs=useMemo(()=>shuffle(questions).slice(0,Math.min(questions.length,25)).map(q=>{const opts=shuffle([q.correct,...q.wrong]);return{...q,opts,ci:opts.indexOf(q.correct)}}),[])
  const [idx,setIdx]=useState(0),[sel,setSel]=useState(null),[score,setScore]=useState(0),[done,setDone]=useState(false)
  const q=qs[idx],answered=sel!==null
  const handle=i=>{if(answered)return;setSel(i);if(i===q.ci){setScore(s=>s+1);onAddCorks(3)}}
  const next=()=>{if(idx+1>=qs.length)setDone(true);else{setIdx(i=>i+1);setSel(null)}}
  if(done)return(
    <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'36px 28px',textAlign:'center'}}>
      <div style={{width:1,height:36,background:H.red,margin:'0 auto 22px'}}/>
      <div style={{fontFamily:H.display,fontSize:24,color:H.black,fontWeight:700,marginBottom:8}}>Abgeschlossen.</div>
      <div style={{fontSize:13,color:H.grayMid,fontFamily:H.body,marginBottom:26,lineHeight:1.7}}>{score} von {qs.length} richtig</div>
      <div style={{background:H.cream,border:'1px solid rgba(196,150,42,0.22)',borderRadius:4,padding:'14px 32px',marginBottom:26,display:'flex',alignItems:'center',gap:12,justifyContent:'center'}}>
        <img src={CORK_IMG} alt="" style={{width:22,height:13}}/><span style={{fontFamily:H.display,fontSize:24,color:H.gold,fontWeight:700}}>+{score*3}</span>
      </div>
      <Btn onClick={onDone}>Zurück zur Auswahl</Btn>
    </div>
  )
  return(
    <div style={{flex:1,display:'flex',flexDirection:'column',overflowY:'auto',padding:'16px 22px'}}>
      <div style={{marginBottom:16}}>
        <div style={{fontSize:9,color:H.red,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body,marginBottom:8}}>{title}</div>
        <Progbar val={(idx/qs.length)*100} thin/><div style={{fontSize:10,color:H.grayLight,fontFamily:H.body,marginTop:5,textAlign:'right'}}>{idx+1} / {qs.length}</div>
      </div>
      <div style={{fontFamily:H.display,fontSize:19,color:H.black,fontWeight:600,lineHeight:1.4,marginBottom:20}}>{q.q}</div>
      <div style={{display:'flex',flexDirection:'column',gap:9,flex:1}}>
        {q.opts.map((opt,i)=>{
          const isC=i===q.ci,isSel=sel===i
          let bg=H.white,border=`1.5px solid ${H.grayLine}`,color=H.black
          if(answered){if(isC){bg='#EBF5EE';border=`2px solid ${H.green}`;color=H.green}else if(isSel){bg='#F5EAEC';border=`2px solid ${H.red}`;color=H.red}}
          return <button key={i} onClick={()=>handle(i)} style={{padding:'13px 16px',borderRadius:4,background:bg,border,color,fontSize:13,fontFamily:H.body,textAlign:'left',cursor:answered?'default':'pointer',transition:'all 0.18s',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
            <span>{opt}</span>{answered&&isC&&<span style={{fontWeight:700}}>✓</span>}{answered&&isSel&&!isC&&<span style={{fontWeight:700}}>✗</span>}
          </button>
        })}
      </div>
      {answered&&<div style={{marginTop:12}}>
        <div style={{padding:'10px 14px',background:sel===q.ci?'#EBF5EE':'#F5EAEC',borderRadius:4,marginBottom:10,fontSize:13,color:sel===q.ci?H.green:H.red,fontFamily:H.body,display:'flex',alignItems:'center',gap:8}}>
          {sel===q.ci?<><span>Richtig.</span><div style={{marginLeft:'auto',display:'flex',alignItems:'center',gap:4}}><img src={CORK_IMG} alt="" style={{width:14,height:9}}/><span style={{fontWeight:700}}>+3</span></div></>:`Richtig: ${q.opts[q.ci]}`}
        </div>
        <Btn onClick={next}>{idx+1>=qs.length?'Abschließen':'Weiter'}</Btn>
      </div>}
    </div>
  )
}


