// ─── SCREEN: WISSENS-CHECK ────────────────────────────────────────────────────
function WissensCheckScreen({onComplete}) {
  const qs=useMemo(()=>shuffle([...REGIONEN_Q,...REBSORTEN_Q]).slice(0,6).map(q=>{const opts=shuffle([q.correct,...q.wrong]);return{...q,opts,ci:opts.indexOf(q.correct)}}),[])
  const [idx,setIdx]=useState(0),[sel,setSel]=useState(null),[score,setScore]=useState(0)
  const q=qs[idx],answered=sel!==null
  const handle=i=>{if(answered)return;setSel(i);if(i===q.ci)setScore(s=>s+1)}
  const next=()=>{const ns=score+(sel===q.ci?1:0);if(idx+1>=qs.length){const p=Math.round((ns/qs.length)*100);onComplete(p>=70?'kenner':p>=40?'entdecker':'einsteiger',p)}else{setIdx(i=>i+1);setSel(null)}}
  return(
    <Screen>
      <TopBar right={<div style={{fontSize:12,color:H.grayMid,fontFamily:H.body}}>{idx+1}/{qs.length}</div>}/>
      <div style={{padding:'0 22px 8px'}}><Progbar val={(idx/qs.length)*100}/></div>
      <div style={{flex:1,display:'flex',flexDirection:'column',padding:'18px 22px',overflowY:'auto'}}>
        <div style={{fontSize:9,color:H.red,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body,marginBottom:14}}>Wissens · Check</div>
        <div style={{fontFamily:H.display,fontSize:20,color:H.black,fontWeight:600,lineHeight:1.38,marginBottom:24}}>{q.q}</div>
        <div style={{display:'flex',flexDirection:'column',gap:9,flex:1}}>
          {q.opts.map((opt,i)=>{const isC=i===q.ci,isSel=sel===i;let bg=H.white,border=`1.5px solid ${H.grayLine}`,color=H.black;if(answered){if(isC){bg='#EBF5EE';border=`2px solid ${H.green}`;color=H.green}else if(isSel){bg='#F5EAEC';border=`2px solid ${H.red}`;color=H.red}}
            return <button key={i} onClick={()=>handle(i)} style={{padding:'13px 16px',borderRadius:4,background:bg,border,color,fontSize:13,fontFamily:H.body,textAlign:'left',cursor:answered?'default':'pointer',transition:'all 0.18s',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <span>{opt}</span>{answered&&isC&&<span style={{fontWeight:700}}>✓</span>}{answered&&isSel&&!isC&&<span style={{fontWeight:700}}>✗</span>}
            </button>
          })}
        </div>
        {answered&&<div style={{marginTop:12}}>
          <div style={{padding:'10px 14px',background:sel===q.ci?'#EBF5EE':'#F5EAEC',borderRadius:4,marginBottom:10,fontSize:13,color:sel===q.ci?H.green:H.red,fontFamily:H.body}}>{sel===q.ci?'Richtig.':`Richtig: ${q.opts[q.ci]}`}</div>
          <Btn onClick={next}>{idx+1>=qs.length?'Auswertung':'Weiter'}</Btn>
        </div>}
      </div>
    </Screen>
  )
}

