// ─── SCREEN: COMMUNITY ────────────────────────────────────────────────────────
function CommunityScreen({corks,onBack}) {
  const [view,setView]=useState('list') // list | detail | create
  const [activeCommunity,setActiveCommunity]=useState(null)
  const [joined,setJoined]=useState({})
  const [newMsg,setNewMsg]=useState('')
  const [localPosts,setLocalPosts]=useState({})
  const [showCreate,setShowCreate]=useState(false)
  const [newComm,setNewComm]=useState({name:'',desc:'',type:'rebsorte'})
  const [customComms,setCustomComms]=useState([])

  const allCommunities=[...COMMUNITIES,...customComms]
  const comm=allCommunities.find(c=>c.id===activeCommunity)
  const posts=comm?[...(localPosts[comm.id]||[]),...comm.posts]:[]

  const sendMsg=()=>{
    if(!newMsg.trim())return
    const msg={id:Date.now(),user:'Du',avatar:'D',time:'gerade eben',text:newMsg.trim(),likes:0,replies:0,isOwn:true}
    setLocalPosts(p=>({...p,[comm.id]:[msg,...(p[comm.id]||[])]}))
    setNewMsg('')
  }

  const createCommunity=()=>{
    if(!newComm.name.trim())return
    const c={id:`custom-${Date.now()}`,title:newComm.name,type:newComm.type,members:1,
      tag:'Privat',tagColor:H.grayDark,joined:true,private:true,
      desc:newComm.desc||'Deine private Community.',posts:[],reward:''}
    setCustomComms(p=>[...p,c])
    setJoined(j=>({...j,[c.id]:true}))
    setShowCreate(false)
    setNewComm({name:'',desc:'',type:'rebsorte'})
  }

  // Community list
  if(view==='list') return(
    <Screen bg={H.cream}>
      <div style={{padding:'52px 22px 14px',background:H.white,borderBottom:`1px solid ${H.grayLine}`,display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        <button onClick={onBack} style={{fontSize:24,cursor:'pointer',color:H.black,background:'none',border:'none',lineHeight:1}}>‹</button>
        <CorkBadge count={corks} small/>
      </div>
      <div style={{flex:1,overflowY:'auto',padding:'18px 18px 36px'}}>
        <div style={{fontSize:9,color:H.red,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body,marginBottom:4}}>Communities</div>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-end',marginBottom:6}}>
          <div style={{fontFamily:H.display,fontSize:22,color:H.black,fontWeight:600}}>Wein-Communities.</div>
        </div>
        <div style={{fontSize:13,color:H.grayMid,fontFamily:H.body,lineHeight:1.7,marginBottom:20}}>Tausche dich mit anderen Weinliebhabern aus — nach Region, Rebsorte oder Thema.</div>

        {/* Create new private community */}
        <button onClick={()=>setShowCreate(true)} style={{width:'100%',background:H.black,borderRadius:4,padding:'14px 18px',marginBottom:16,border:'1px solid rgba(196,150,42,0.25)',cursor:'pointer',textAlign:'left',display:'flex',alignItems:'center',gap:14}}>
          <div style={{width:36,height:36,borderRadius:3,background:'rgba(196,150,42,0.15)',border:'1px solid rgba(196,150,42,0.3)',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:20,color:H.gold}}>+</div>
          <div style={{flex:1}}>
            <div style={{fontFamily:H.display,fontSize:15,color:H.white,fontWeight:600}}>Private Community erstellen</div>
            <div style={{fontSize:11,color:'rgba(255,255,255,0.38)',fontFamily:H.body,marginTop:1}}>Nur für eingeladene Mitglieder · deine Regeln</div>
          </div>
          <span style={{fontSize:9,background:'rgba(196,150,42,0.2)',color:H.gold,borderRadius:2,padding:'3px 8px',fontFamily:H.body,fontWeight:600}}>NEU</span>
        </button>

        {/* Custom communities */}
        {customComms.map(c=>(
          <div key={c.id} style={{background:H.white,borderRadius:4,padding:'16px',marginBottom:10,border:`1px solid ${H.grayLine}`,position:'relative',overflow:'hidden'}}>
            <div style={{position:'absolute',top:0,left:0,right:0,height:3,background:H.grayDark}}/>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:8}}>
              <div style={{flex:1}}>
                <div style={{display:'flex',gap:6,alignItems:'center',marginBottom:4}}>
                  <span style={{fontSize:9,fontWeight:700,background:'rgba(61,61,61,0.1)',color:H.grayDark,borderRadius:2,padding:'2px 7px',fontFamily:H.body}}>PRIVAT</span>
                </div>
                <div style={{fontFamily:H.display,fontSize:16,color:H.black,fontWeight:600}}>{c.title}</div>
                <div style={{fontSize:12,color:H.grayMid,fontFamily:H.body,marginTop:2}}>{c.desc}</div>
              </div>
            </div>
            <button onClick={()=>{setActiveCommunity(c.id);setView('detail')}} style={{width:'100%',background:H.grayBg,border:`1px solid ${H.grayLine}`,borderRadius:3,padding:'8px',cursor:'pointer',fontSize:12,color:H.grayDark,fontFamily:H.body,fontWeight:600}}>Öffnen</button>
          </div>
        ))}

        {/* Public communities */}
        <div style={{fontSize:9,color:H.grayLight,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:H.body,marginBottom:12}}>Öffentliche Communities</div>
        {COMMUNITIES.map(c=>(
          <div key={c.id} style={{background:H.white,borderRadius:4,padding:'16px',marginBottom:10,border:`1px solid ${H.grayLine}`,position:'relative',overflow:'hidden',cursor:'pointer'}} onClick={()=>{setActiveCommunity(c.id);setView('detail')}}>
            <div style={{position:'absolute',top:0,left:0,right:0,height:3,background:c.tagColor}}/>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:8}}>
              <div style={{flex:1,paddingRight:10}}>
                <div style={{display:'flex',gap:6,alignItems:'center',marginBottom:5}}>
                  <span style={{fontSize:9,fontWeight:700,background:c.tagColor+'18',color:c.tagColor,borderRadius:2,padding:'2px 7px',fontFamily:H.body}}>{c.tag}</span>
                  <span style={{fontSize:10,color:H.grayLight,fontFamily:H.body}}>{c.members.toLocaleString('de-DE')} Mitglieder</span>
                </div>
                <div style={{fontFamily:H.display,fontSize:16,color:H.black,fontWeight:600,marginBottom:3}}>{c.title}</div>
                <div style={{fontSize:12,color:H.grayMid,fontFamily:H.body,lineHeight:1.55}}>{c.desc}</div>
              </div>
            </div>
            <div style={{display:'flex',gap:8,alignItems:'center'}}>
              <div style={{flex:1,fontSize:11,color:H.grayLight,fontFamily:H.body}}>
                {c.posts[0]&&`"${c.posts[0].text.slice(0,45)}..."`}
              </div>
              <button onClick={e=>{e.stopPropagation();setJoined(j=>({...j,[c.id]:!j[c.id]}))}}
                style={{background:joined[c.id]?H.grayBg:c.tagColor,color:joined[c.id]?H.grayDark:H.white,border:joined[c.id]?`1px solid ${H.grayLine}`:'none',borderRadius:3,padding:'7px 16px',cursor:'pointer',fontSize:12,fontFamily:H.body,fontWeight:600,whiteSpace:'nowrap',flexShrink:0}}>
                {joined[c.id]?'Beigetreten':'Beitreten'}
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Create modal */}
      {showCreate&&(
        <div style={{position:'absolute',inset:0,background:'rgba(0,0,0,0.6)',zIndex:50,display:'flex',alignItems:'flex-end'}}>
          <div style={{background:H.white,borderRadius:'16px 16px 0 0',width:'100%',padding:'24px 20px 44px'}}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
              <div style={{fontFamily:H.display,fontSize:18,color:H.black,fontWeight:700}}>Private Community</div>
              <button onClick={()=>setShowCreate(false)} style={{fontSize:20,color:H.grayMid,background:'none',border:'none',cursor:'pointer'}}>✕</button>
            </div>
            <div style={{fontSize:9,color:H.grayMid,letterSpacing:'0.12em',textTransform:'uppercase',fontFamily:H.body,marginBottom:6}}>Name</div>
            <input value={newComm.name} onChange={e=>setNewComm(p=>({...p,name:e.target.value}))}
              placeholder="z.B. Riesling-Freunde Hamburg" style={{width:'100%',border:`1.5px solid ${H.grayLine}`,borderRadius:4,padding:'12px',fontFamily:H.body,fontSize:13,color:H.black,outline:'none',marginBottom:12,boxSizing:'border-box'}}/>
            <div style={{fontSize:9,color:H.grayMid,letterSpacing:'0.12em',textTransform:'uppercase',fontFamily:H.body,marginBottom:6}}>Beschreibung (optional)</div>
            <input value={newComm.desc} onChange={e=>setNewComm(p=>({...p,desc:e.target.value}))}
              placeholder="Worum geht es in eurer Community?" style={{width:'100%',border:`1.5px solid ${H.grayLine}`,borderRadius:4,padding:'12px',fontFamily:H.body,fontSize:13,color:H.black,outline:'none',marginBottom:16,boxSizing:'border-box'}}/>
            <div style={{background:'#EBF5EE',borderRadius:4,padding:'10px 14px',marginBottom:16,display:'flex',gap:8,alignItems:'flex-start'}}>
              <span style={{color:H.green,fontSize:14,flexShrink:0}}>🔒</span>
              <div style={{fontSize:12,color:H.grayDark,fontFamily:H.body,lineHeight:1.6}}>Private Communities sind nur für eingeladene Mitglieder sichtbar. Du kannst Freunde per Link einladen.</div>
            </div>
            <Btn onClick={createCommunity} disabled={!newComm.name.trim()}>Community erstellen</Btn>
          </div>
        </div>
      )}
    </Screen>
  )

  // Community detail / feed
  if(!comm) return null
  return(
    <Screen bg={H.cream}>
      {/* Header */}
      <div style={{padding:'52px 18px 0',background:H.white,borderBottom:`1px solid ${H.grayLine}`,position:'relative'}}>
        <div style={{position:'absolute',top:0,left:0,right:0,height:4,background:comm.tagColor}}/>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
          <button onClick={()=>setView('list')} style={{fontSize:24,cursor:'pointer',color:H.black,background:'none',border:'none',lineHeight:1}}>‹</button>
          <CorkBadge count={corks} small/>
        </div>
        <div style={{display:'flex',gap:6,alignItems:'center',marginBottom:4}}>
          <span style={{fontSize:9,fontWeight:700,background:comm.tagColor+'18',color:comm.tagColor,borderRadius:2,padding:'2px 7px',fontFamily:H.body}}>{comm.tag}</span>
          <span style={{fontSize:10,color:H.grayLight,fontFamily:H.body}}>{(comm.members+(joined[comm.id]?1:0)).toLocaleString('de-DE')} Mitglieder</span>
        </div>
        <div style={{fontFamily:H.display,fontSize:19,color:H.black,fontWeight:700,marginBottom:3}}>{comm.title}</div>
        <div style={{fontSize:12,color:H.grayMid,fontFamily:H.body,lineHeight:1.55,marginBottom:12}}>{comm.desc}</div>
        <div style={{display:'flex',gap:8,paddingBottom:12}}>
          <button onClick={()=>setJoined(j=>({...j,[comm.id]:!j[comm.id]}))}
            style={{background:joined[comm.id]?H.grayBg:comm.tagColor,color:joined[comm.id]?H.grayDark:H.white,border:joined[comm.id]?`1px solid ${H.grayLine}`:'none',borderRadius:3,padding:'8px 18px',cursor:'pointer',fontSize:12,fontFamily:H.body,fontWeight:600}}>
            {joined[comm.id]?'Beigetreten ✓':'Community beitreten'}
          </button>
        </div>
      </div>

      {/* Feed */}
      <div style={{flex:1,overflowY:'auto',padding:'14px 16px 80px'}}>
        {posts.map((post,i)=>(
          <div key={post.id||i} style={{background:H.white,borderRadius:4,padding:'14px 16px',marginBottom:10,border:`1px solid ${post.isOwn?comm.tagColor:H.grayLine}`,borderLeft:post.isOwn?`4px solid ${comm.tagColor}`:`1px solid ${H.grayLine}`}}>
            <div style={{display:'flex',gap:10,alignItems:'center',marginBottom:8}}>
              <div style={{width:30,height:30,borderRadius:'50%',background:post.isOwn?comm.tagColor:H.grayBg,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
                <span style={{fontSize:12,fontWeight:700,color:post.isOwn?H.white:H.grayDark,fontFamily:H.body}}>{post.avatar}</span>
              </div>
              <div style={{flex:1}}>
                <div style={{fontSize:13,fontWeight:600,color:H.black,fontFamily:H.body}}>{post.user}</div>
                <div style={{fontSize:10,color:H.grayLight,fontFamily:H.body}}>{post.time}</div>
              </div>
            </div>
            <div style={{fontSize:13,color:H.grayDark,fontFamily:H.body,lineHeight:1.7,marginBottom:10}}>{post.text}</div>
            <div style={{display:'flex',gap:16,alignItems:'center'}}>
              <button style={{background:'none',border:'none',cursor:'pointer',display:'flex',alignItems:'center',gap:4}}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z" stroke={H.grayLight} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <span style={{fontSize:11,color:H.grayLight,fontFamily:H.body}}>{post.likes}</span>
              </button>
              <button style={{background:'none',border:'none',cursor:'pointer',display:'flex',alignItems:'center',gap:4}}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z" stroke={H.grayLight} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <span style={{fontSize:11,color:H.grayLight,fontFamily:H.body}}>{post.replies} Antworten</span>
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Message input */}
      <div style={{position:'absolute',bottom:0,left:0,right:0,background:H.white,borderTop:`1px solid ${H.grayLine}`,padding:'10px 14px 24px',display:'flex',gap:10,alignItems:'flex-end'}}>
        <div style={{flex:1,background:H.grayBg,borderRadius:22,padding:'10px 16px',border:`1px solid ${H.grayLine}`,display:'flex',alignItems:'center'}}>
          <input value={newMsg} onChange={e=>setNewMsg(e.target.value)}
            onKeyDown={e=>e.key==='Enter'&&sendMsg()}
            placeholder="Schreib etwas..." style={{background:'none',border:'none',outline:'none',fontFamily:H.body,fontSize:13,color:H.black,width:'100%'}}/>
        </div>
        <button onClick={sendMsg} style={{width:40,height:40,borderRadius:'50%',background:newMsg.trim()?comm.tagColor:H.grayLine,border:'none',cursor:newMsg.trim()?'pointer':'default',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,transition:'background 0.2s'}}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none"><line x1="22" y1="2" x2="11" y2="13" stroke={H.white} strokeWidth="2" strokeLinecap="round"/><polygon points="22 2 15 22 11 13 2 9 22 2" stroke={H.white} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
        </button>
      </div>
    </Screen>
  )
}

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [screen,setScreen]=useState('welcome')
  const [level,setLevel]=useState(null),[pct,setPct]=useState(0)
  const [dna,setDna]=useState(null),[liked,setLiked]=useState([]),[supers,setSupers]=useState([])
  const [corks,setCorks]=useState(0)
  const [corks12m,setCorks12m]=useState(0)
  const [streak,setStreak]=useState(3)
  const [showStatus,setShowStatus]=useState(false)
  const [collected,setCollected]=useState({})
  const [keller,setKeller]=useState([])

  const addCorks=n=>{setCorks(c=>c+n);setCorks12m(c=>c+n)}
  const addStreak=()=>setStreak(s=>s+1)
  const onCollect=(key,data)=>setCollected(p=>({...p,[key]:data}))

  if(showStatus)return(
    <div style={{width:'100vw',height:'100dvh',display:'flex',alignItems:'center',justifyContent:'center',background:'#0D0608'}}>
      <StatusScreen corks={corks} corks12m={corks12m} streak={streak} onClose={()=>setShowStatus(false)}/>
    </div>
  )

  const screens={
    welcome:<WelcomeScreen onStart={()=>setScreen('quiz')}/>,
    quiz:<WissensCheckScreen onComplete={(l,p)=>{setLevel(l);setPct(p);addCorks(p>=70?15:p>=40?10:5);setScreen('quiz-result')}}/>,
    'quiz-result':<QuizResultScreen level={level} pct={pct} corks={corks} onNext={()=>setScreen('dna')}/>,
    dna:<TasteDNAScreen onComplete={(d,l,s)=>{setDna(d);setLiked(l);setSupers(s);addCorks(l.length*1+s.length*2);setScreen('dna-result')}}/>,
    'dna-result':<DNAResultScreen dna={dna} liked={liked} supers={supers} onNext={()=>setScreen('home')}/>,
    home:<HomeScreen liked={liked} corks={corks} corks12m={corks12m} streak={streak} onNav={s=>setScreen(s)} onOpenStatus={()=>setShowStatus(true)}/>,
    learn:<LearnScreen corks={corks} onAddCorks={addCorks} onBack={()=>setScreen('home')}/>,
    daily:<DailyDoseScreen corks={corks} corks12m={corks12m} streak={streak} onAddCorks={addCorks} onAddStreak={addStreak} onBack={()=>setScreen('home')}/>,
    discover:<DiscoverScreen liked={liked} onBack={()=>setScreen('home')}/>,
    winzer:<WinzerCollectionScreen collected={collected} onCollect={onCollect} onAddCorks={addCorks} onBack={()=>setScreen('home')}/>,
    keller:<WeinkellerScreen keller={keller} onUpdateKeller={setKeller} onBack={()=>setScreen('home')}/>,
    community:<CommunityScreen corks={corks} onBack={()=>setScreen('home')}/>,
    cert:<StatusScreen corks={corks} corks12m={corks12m} streak={streak} onClose={()=>setScreen('home')}/>,
  }

  return(
    <div style={{width:'100vw',height:'100dvh',display:'flex',alignItems:'center',justifyContent:'center',background:'#0D0608'}}>
      {screens[screen]||screens.home}
    </div>
  )
}
